// src/components/FormAluno.js
import React, { useState, useEffect } from 'react';
import axios from 'axios';

function FormAluno({ onNovoAluno, alunoEditando, onFimEdicao }) {
  // Campos de texto existentes
  const [nome, setNome] = useState('');
  const [ra, setRa] = useState('');
  const [periodoId, setPeriodoId] = useState('');
  const [mensagem, setMensagem] = useState('');

  // Novos campos:
  const [usuario, setUsuario] = useState('');
  const [senha, setSenha] = useState('');
  const [role, setRole] = useState('aluno'); // valor padrão = "aluno"

  // Lista de períodos
  const [periodos, setPeriodos] = useState([]);

  useEffect(() => {
    axios.get('/api/periodos')
      .then(res => setPeriodos(res.data))
      .catch(() => setPeriodos([]));
  }, []);

  // Quando estivermos editando, preenche os campos
  useEffect(() => {
    if (alunoEditando) {
      setNome(alunoEditando.nome || '');
      setRa(alunoEditando.ra || '');
      setPeriodoId(alunoEditando.periodo_id != null ? String(alunoEditando.periodo_id) : '');
      setUsuario(alunoEditando.usuario || '');
      setRole(alunoEditando.role || 'aluno');
      setSenha(''); // não exibir senha antiga
    } else {
      setNome('');
      setRa('');
      setPeriodoId('');
      setUsuario('');
      setSenha('');
      setRole('aluno');
    }
    setMensagem('');
  }, [alunoEditando]);

  // Validações simples
  function validarNomeCompleto(valor) {
    const partes = valor.trim().split(' ').filter(p => p.length >= 2);
    return partes.length >= 2;
  }
  function validarRA(ra) {
    return /^\d{1,9}$/.test(ra);
  }

  const handleSubmit = (e) => {
    e.preventDefault();
    setMensagem('');

    if (!validarNomeCompleto(nome)) {
      setMensagem("Informe nome e sobrenome (cada um com ao menos 2 letras)!");
      return;
    }
    if (!validarRA(ra)) {
      setMensagem("O RA deve conter apenas números e até 9 dígitos!");
      return;
    }
    if (!usuario.trim()) {
      setMensagem("Insira um login (usuário) válido!");
      return;
    }
    if (!alunoEditando && senha.length < 4) {
      setMensagem("Senha deve ter no mínimo 4 caracteres!");
      return;
    }
    if (!periodoId) {
      setMensagem("Selecione um período!");
      return;
    }

    const dados = {
      nome,
      ra,
      periodo_id: periodoId,
      usuario,
      senha,
      role
    };

    if (alunoEditando) {
      const payload = { nome, ra, periodo_id: periodoId, usuario, role };
      if (senha) payload.senha = senha;

      axios.put(`/api/alunos/${alunoEditando.id}`, payload)
        .then(() => {
          setMensagem('Aluno atualizado com sucesso!');
          setNome(''); setRa(''); setPeriodoId('');
          setUsuario(''); setSenha(''); setRole('aluno');
          onNovoAluno();
          onFimEdicao();
        })
        .catch(err => {
          setMensagem(err.response?.data?.error || 'Erro ao atualizar aluno.');
        });

    } else {
      axios.post('/api/alunos', dados)
        .then(() => {
          setMensagem('Aluno cadastrado com sucesso!');
          setNome(''); setRa(''); setPeriodoId('');
          setUsuario(''); setSenha(''); setRole('aluno');
          onNovoAluno();
        })
        .catch(err => {
          setMensagem(err.response?.data?.error || 'Erro ao cadastrar aluno.');
        });
    }
  };

  return (
    <div className="bg-white mx-auto w-full max-w-md md:max-w-lg lg:max-w-xl rounded-2xl p-6 shadow-md">
      <form onSubmit={handleSubmit} autoComplete="off" className="space-y-6">

        <h2 className="text-2xl font-bold text-gray-800">
          {alunoEditando ? 'Editar Aluno' : 'Cadastrar Novo Aluno'}
        </h2>

        {/* Nome Completo */}
        <div>
          <label className="block text-gray-700 font-medium mb-1">
            Nome Completo
          </label>
          <input
            type="text"
            className="w-full border border-gray-300 rounded-lg px-3 py-2 focus:outline-none focus:ring focus:ring-blue-200"
            value={nome}
            onChange={e => setNome(e.target.value)}
            placeholder="Ex.: João Silva"
            required
          />
        </div>

        {/* RA e Período em linha no desktop, empilhado no mobile */}
        <div className="flex flex-col md:flex-row md:space-x-4">
          {/* RA */}
          <div className="flex-1">
            <label className="block text-gray-700 font-medium mb-1">
              RA
            </label>
            <input
              type="text"
              className="w-full border border-gray-300 rounded-lg px-3 py-2 focus:outline-none focus:ring focus:ring-blue-200"
              value={ra}
              onChange={e => setRa(e.target.value.replace(/\D/g, '').slice(0, 9))}
              maxLength={9}
              placeholder="Somente números"
              required
            />
          </div>

          {/* Período */}
          <div className="flex-1 mt-4 md:mt-0">
            <label className="block text-gray-700 font-medium mb-1">
              Período
            </label>
            <select
              className="w-full border border-gray-300 rounded-lg px-3 py-2 focus:outline-none focus:ring focus:ring-blue-200"
              value={periodoId}
              onChange={e => setPeriodoId(e.target.value)}
              required
            >
              <option value="">Selecione...</option>
              {periodos.map(periodo => (
                <option key={periodo.id} value={periodo.id}>
                  {periodo.nome} ({periodo.turno})
                </option>
              ))}
            </select>
          </div>
        </div>

        {/* Login (usuário) e Permissão (role) */}
        <div className="flex flex-col md:flex-row md:space-x-4">
          {/* Usuário */}
          <div className="flex-1">
            <label className="block text-gray-700 font-medium mb-1">
              Login (usuário)
            </label>
            <input
              type="text"
              className="w-full border border-gray-300 rounded-lg px-3 py-2 focus:outline-none focus:ring focus:ring-blue-200"
              value={usuario}
              onChange={e => setUsuario(e.target.value)}
              placeholder="Ex.: matricula123"
              required
            />
          </div>

          {/* Permissão */}
          <div className="flex-1 mt-4 md:mt-0">
            <label className="block text-gray-700 font-medium mb-1">
              Permissão
            </label>
            <select
              className="w-full border border-gray-300 rounded-lg px-3 py-2 focus:outline-none focus:ring focus:ring-blue-200"
              value={role}
              onChange={e => setRole(e.target.value)}
            >
              <option value="aluno">Aluno</option>
              <option value="recepcao">Recepção</option>
            </select>
          </div>
        </div>

        {/* Senha */}
        <div>
          <label className="block text-gray-700 font-medium mb-1">
            {alunoEditando
              ? 'Nova senha (deixe em branco para manter)'
              : 'Senha'}
          </label>
          <input
            type="password"
            className="w-full border border-gray-300 rounded-lg px-3 py-2 focus:outline-none focus:ring focus:ring-blue-200"
            value={senha}
            onChange={e => setSenha(e.target.value)}
            placeholder={alunoEditando ? '••••••••' : '••••••••'}
            required={!alunoEditando}
          />
        </div>

        {/* Botões de ação */}
        <div className="flex flex-col md:flex-row md:space-x-4">
          <button
            type="submit"
            className="flex-1 bg-blue-600 text-white font-semibold py-2 px-4 rounded-full hover:bg-blue-700 transition"
          >
            {alunoEditando ? 'Atualizar' : 'Cadastrar'}
          </button>

          {alunoEditando && (
            <button
              type="button"
              className="flex-1 bg-red-500 text-white font-semibold py-2 px-4 rounded-full hover:bg-red-600 transition mt-4 md:mt-0"
              onClick={onFimEdicao}
            >
              Cancelar
            </button>
          )}
        </div>

        {/* Feedback de erro ou sucesso */}
        {mensagem && (
          <p className="mt-4 text-center text-red-600">{mensagem}</p>
        )}
      </form>
    </div>
  );
}

export default FormAluno;
